INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-d0d1b9a2-moex-00105', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司為奶瓶批發商，奶瓶每個售價為$100。X3年3月24日賒銷A客戶100個奶瓶，經議價後給予A 客戶商業折扣，以每個$80出售，該筆賒銷交易付款條件為2/10、n/30。X3年3月30日A客戶退回15 個奶瓶，X3年4月2日A客戶償還該筆賒銷交易總價之25%，X3年4月3日A客戶償還該筆賒銷交易 總價之50%，X3年4月4日A客戶又退回5個奶瓶，X3年4月5日A客戶將剩餘欠款清償。A客戶自 該筆賒購交易取得之現金折扣共計多少？', '["$0", "$34", "$102", "$136"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00106', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '丙公司於X1年8月1日按$96,737加計應計利息購入一張乙公司所發行的債券，並支付手續費$182。債 券之面額$100,000，票面利率6%，每年12月31日付息，到期日為X3年12月31日。丙公司持有該債 券的經營模式為出售以賺取公允價值變動的利益。若X1年12月31日債券的市價為$97,300，則X1年度 丙公司綜合損益表上列示的透過損益按公允價值衡量之金融資產損益金額為何？', '["利益$263", "利益$381", "利益$482", "利益$563"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00107', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X3年1月1日以$2,000,000購入乙公司普通股股份30%，投資成本與取得股權淨值之金額無差 額，X3年7月1日乙公司宣告並發放現金股利$1,200,000，且乙公司X3年度淨利為$2,500,000，則X3年 12月31日甲公司對乙公司投資帳戶之金額是多少？', '["$960,000", "$2,390,000", "$2,570,000", "$3,110,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00108', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年1月1日以每股$35購入乙公司面額$10的股票2,000股，乙公司於X1年5月1日發放每 股現金股利$2以及10%股票股利，甲公司在X1年12月31日以每股$40賣出所持有全部乙公司股票，若 甲公司將乙公司股票列為透過損益按公允價值衡量之金融資產，則前述與乙公司有關之股票交易對甲公 司X1年的淨利增加為何？', '["$4,000", "$18,000", "$22,000", "$26,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00109', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '承上題，若甲公司將乙公司股票認列為透過其他綜合損益按公允價值衡量之金融資產，則以上與乙公司有 關之股票交易對甲公司X1年的淨利增加為何？', '["$0", "$4,000", "$18,000", "$22,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00110', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '下列不動產、廠房及設備使用期間之支出，何者須認列為當期費用？', '["廠房之火險保費", "增添機器設備組件，增加機器營運效能", "辦公大樓電梯換新", "將機器設備進行全面檢修，檢修後將延長使用年限2年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00111', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', 'X1年4月1日甲公司購買機器設備$600,000，估計耐用年限為10年，殘值為$50,000。若甲公司採年數 合計法與成本模式後續衡量，則X1年應認列之折舊金額為何？', '["$55,000", "$70,000", "$75,000", "$100,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00112', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年5月1日購入機器一部，成本$1,000,000，估計耐用年限10年，殘值$100,000，採直線法 提列折舊。X4 年底作減損測試，估計該機器未來現金流入總額為$800,000，公允價值減出售成本為 $600,000，使用價值為$540,000，則X4年底甲公司應認列減損損失金額為何？', '["$0", "$40,000", "$70,000", "$130,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00113', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '下列何者將導致應付帳款之貸方餘額上升或借方餘額下降？', '["賒購商品", "賒銷商品", "現金增資", "收到客戶償還帳款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00114', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '乙公司購買一棟大樓，支付購買成本$6,000,000（包括土地公允價值$3,000,000 及房屋公允價值 $3,000,000），另發生代書費$10,000 及房屋移轉之契稅$50,000。下列何者為該不動產當中房屋部分之原 始認列金額？', '["$3,030,000", "$3,050,000", "$3,055,000", "$3,060,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
